#!/usr/bin/env Rscript
args<-commandArgs(trailingOnly=TRUE);get<-function(k){i<-match(k,args);if(is.na(i))stop('Missing ',k);args[i+1]};if(!requireNamespace('limma',quietly=TRUE))stop('limma is required for DMP analysis')
a<-readRDS(get('--analysis'));ss<-read.csv(get('--samplesheet'),check.names=FALSE,stringsAsFactors=FALSE);out<-get('--outdir');dir.create(file.path(out,'complete'),recursive=TRUE,showWarnings=FALSE);dir.create(file.path(out,'significant'),showWarnings=FALSE);m<-if(inherits(a,'SummarizedExperiment'))SummarizedExperiment::assay(a,'mvalue')else a$mvalue;b<-if(inherits(a,'SummarizedExperiment'))SummarizedExperiment::assay(a,'beta')else a$beta
if(nrow(m)==0)stop('No probes remain after filtering. Inspect filtering/filtering_summary.tsv and filtering/probe_lists/removed_probes.tsv; for small cohorts, consider scientifically justified relaxation of --min_detection_rate and/or --max_missing_rate.')
if(ncol(m)<2)stop('DMP analysis requires at least two samples after QC.')
ss<-ss[match(colnames(m),ss$sample_id),,drop=FALSE];design<-model.matrix(as.formula(get('--design')),ss);if(qr(design)$rank<ncol(design))stop('Design matrix is rank-deficient; revise design/covariates');contrast<-get('--contrast');if(contrast==''||is.na(contrast))stop('--contrast is required when --find_dmps true');cts<-strsplit(contrast,',')[[1]];cm<-limma::makeContrasts(contrasts=cts,levels=design);fit<-limma::eBayes(limma::contrasts.fit(limma::lmFit(m,design),cm));fdr<-as.numeric(get('--fdr'));dbthr<-as.numeric(get('--min-abs-delta-beta'));write.table(data.frame(design=get('--design'),contrast=cts),file.path(out,'model_definitions.tsv'),sep='\t',row.names=FALSE,quote=FALSE)
for(ct in colnames(cm)){z<-limma::topTable(fit,coef=ct,number=Inf,sort.by='P');z$probe_id<-rownames(z);z$delta_beta<-NA_real_;safe<-gsub('[^A-Za-z0-9._-]','_',ct);write.table(z,file.path(out,'complete',paste0(safe,'.tsv')),sep='\t',row.names=FALSE,quote=FALSE);write.table(z[z$adj.P.Val<=fdr & abs(z$delta_beta)>=dbthr,,drop=FALSE],file.path(out,'significant',paste0(safe,'.tsv')),sep='\t',row.names=FALSE,quote=FALSE)}
